import React, { useState } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  Stepper,
  Step,
  StepLabel,
  StepButton
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import EditIcon from '@mui/icons-material/Edit';
import SendIcon from '@mui/icons-material/Send';

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [activeStep, setActiveStep] = useState(0);
  const [completed, setCompleted] = useState({});

  const steps = [
    'Enter original testimonial',
    'Get enhanced version',
    'Client verification'
  ];

  const originalText = "The coaching was good. I learned some things that helped me.";
  const enhancedText = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  const handleStep = (step) => () => {
    setActiveStep(step);

    // Mark previous steps as completed
    const newCompleted = {...completed};
    for (let i = 0; i < step; i++) {
      newCompleted[i] = true;
    }
    setCompleted(newCompleted);
  };

  const handleNext = () => {
    const newCompleted = {...completed};
    newCompleted[activeStep] = true;
    setCompleted(newCompleted);
    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  const handleReset = () => {
    setActiveStep(0);
    setCompleted({});
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 6, md: 8 },
          pb: { xs: 8, md: 10 },
          position: 'relative',
          minHeight: '80vh',
          display: 'flex',
          alignItems: 'center'
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg" sx={{ position: 'relative' }}>
          <Box sx={{ display: 'flex', flexDirection: { xs: 'column', md: 'row' }, alignItems: 'center' }}>
            {/* Left side - Hero text */}
            <Box sx={{ width: { xs: '100%', md: '50%' }, pr: { md: 6 }, mb: { xs: 6, md: 0 } }}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="Testimonial Enhancement"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography 
                variant="h2" 
                component="h1" 
                gutterBottom
                sx={{ 
                  fontWeight: 700,
                  fontSize: { xs: '2.5rem', md: '3.5rem' },
                  lineHeight: 1.2
                }}
              >
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Transform bland client feedback into compelling stories that showcase real results. Capture the emotion, transformation, and impact your clients experienced.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  sx={{ px: 3, py: 1.5 }}
                  endIcon={<ArrowForwardIcon />}
                >
                  Enhance a Testimonial
                </Button>

                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ px: 3, py: 1.5 }}
                  onClick={handleReset}
                >
                  Try Demo
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 1.5 }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="body2" color="text.secondary">
                  <Box component="span" sx={{ fontWeight: 600, color: 'text.primary' }}>4.9/5</Box> from 200+ users
                </Typography>
              </Box>
            </Box>

            {/* Right side - Interactive Demo */}
            <Box 
              sx={{ 
                width: { xs: '100%', md: '50%' },
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'flex-start',
                mt: { xs: 2, md: 0 }
              }}
            >
              <Card 
                elevation={3}
                sx={{ 
                  width: '100%', 
                  maxWidth: 450,
                  borderRadius: 3,
                  overflow: 'hidden',
                  boxShadow: '0 10px 40px rgba(0, 0, 0, 0.1)'
                }}
              >
                <Box 
                  sx={{ 
                    bgcolor: 'grey.50', 
                    p: 2,
                    borderBottom: '1px solid rgba(0, 0, 0, 0.08)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between'
                  }}
                >
                  <Typography variant="subtitle1" fontWeight={600}>
                    Testimonial Enhancer
                  </Typography>
                  <Box sx={{ display: 'flex', gap: 1 }}>
                    <Box sx={{ width: 12, height: 12, borderRadius: '50%', bgcolor: '#FF605C' }} />
                    <Box sx={{ width: 12, height: 12, borderRadius: '50%', bgcolor: '#FFBD44' }} />
                    <Box sx={{ width: 12, height: 12, borderRadius: '50%', bgcolor: '#00CA4E' }} />
                  </Box>
                </Box>

                <Box sx={{ p: 3 }}>
                  <Stepper activeStep={activeStep} alternativeLabel>
                    {steps.map((label, index) => (
                      <Step key={label} completed={completed[index]}>
                        <StepButton onClick={handleStep(index)}>
                          {label}
                        </StepButton>
                      </Step>
                    ))}
                  </Stepper>

                  <Box sx={{ mt: 4, minHeight: 300 }}>
                    {activeStep === 0 && (
                      <Fade in={activeStep === 0}>
                        <Box>
                          <Typography variant="subtitle2" gutterBottom color="text.secondary">
                            ORIGINAL TESTIMONIAL
                          </Typography>
                          <TextField
                            fullWidth
                            multiline
                            rows={4}
                            variant="outlined"
                            value={originalText}
                            placeholder="Enter your client's original testimonial here..."
                            sx={{ mb: 3 }}
                          />
                          <Button 
                            variant="contained" 
                            color="primary"
                            fullWidth
                            size="large"
                            onClick={handleNext}
                            sx={{ mt: 2 }}
                          >
                            Enhance This Testimonial
                          </Button>
                        </Box>
                      </Fade>
                    )}

                    {activeStep === 1 && (
                      <Fade in={activeStep === 1}>
                        <Box>
                          <Typography variant="subtitle2" gutterBottom color="text.secondary">
                            ENHANCED TESTIMONIAL
                          </Typography>
                          <Paper 
                            elevation={0} 
                            sx={{ 
                              p: 2, 
                              mb: 3, 
                              bgcolor: 'primary.lighter',
                              border: '1px solid',
                              borderColor: 'primary.light',
                              borderRadius: 2
                            }}
                          >
                            <Typography variant="body1">
                              {enhancedText}
                            </Typography>
                          </Paper>
                          <Stack direction="row" spacing={2}>
                            <Button 
                              variant="outlined"
                              startIcon={<EditIcon />}
                              sx={{ flex: 1 }}
                            >
                              Edit
                            </Button>
                            <Button 
                              variant="contained"
                              color="primary"
                              endIcon={<SendIcon />}
                              sx={{ flex: 1 }}
                              onClick={handleNext}
                            >
                              Send for Approval
                            </Button>
                          </Stack>
                        </Box>
                      </Fade>
                    )}

                    {activeStep === 2 && (
                      <Fade in={activeStep === 2}>
                        <Box sx={{ textAlign: 'center' }}>
                          <Box 
                            sx={{ 
                              width: 80, 
                              height: 80, 
                              borderRadius: '50%', 
                              bgcolor: 'success.lighter',
                              color: 'success.main',
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              mx: 'auto',
                              mb: 3
                            }}
                          >
                            <CheckCircleIcon sx={{ fontSize: 40 }} />
                          </Box>
                          <Typography variant="h5" gutterBottom>
                            Testimonial Approved!
                          </Typography>
                          <Typography variant="body1" color="text.secondary" sx={{ mb: 3 }}>
                            Your client has verified this testimonial. It's now ready to use on your website, social media, or marketing materials.
                          </Typography>
                          <Button 
                            variant="contained"
                            color="primary"
                            onClick={handleReset}
                          >
                            Try Another Example
                          </Button>
                        </Box>
                      </Fade>
                    )}
                  </Box>
                </Box>
              </Card>
            </Box>
          </Box>
        </Container>
      </Box>

      {/* How It Works Section */}
      <Box sx={{ py: 10, bgcolor: 'grey.50' }}>
        <Container maxWidth="lg">
          <Box sx={{ textAlign: 'center', mb: 8 }}>
            <Typography variant="h3" component="h2" gutterBottom fontWeight={700}>
              How It Works
            </Typography>
            <Typography variant="subtitle1" color="text.secondary" sx={{ maxWidth: 700, mx: 'auto' }}>
              Transform bland testimonials into powerful stories in three simple steps
            </Typography>
          </Box>

          <Grid container spacing={4} justifyContent="center">
            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  1
                </Box>
                <Typography variant="h5" gutterBottom>
                  Submit raw testimonial
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Paste your client's original words, no matter how brief or bland they might be.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  2
                </Box>
                <Typography variant="h5" gutterBottom>
                  Get enhanced version
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Testy extracts the transformation, emotion, and impact from your client's experience.
                </Typography>
              </Card>
            </Grid>

            <Grid item xs={12} sm={6} md={4}>
              <Card 
                elevation={0} 
                sx={{ 
                  height: '100%',
                  p: 3,
                  borderRadius: 3,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  transition: 'all 0.3s ease',
                  '&:hover': {
                    transform: 'translateY(-5px)',
                    boxShadow: '0 10px 30px rgba(0, 0, 0, 0.1)'
                  }
                }}
              >
                <Box 
                  sx={{ 
                    width: 50, 
                    height: 50, 
                    borderRadius: '50%', 
                    bgcolor: 'primary.light',
                    color: 'primary.main',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontWeight: 700,
                    fontSize: '1.5rem',
                    mb: 2
                  }}
                >
                  3
                </Box>
                <Typography variant="h5" gutterBottom>
                  One-click client approval
                </Typography>
                <Typography variant="body1" color="text.secondary">
                  Send a verification link to your client for instant approval with a single click.
                </Typography>
              </Card>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* CTA Section */}
      <Box sx={{ py: 10 }}>
        <Container maxWidth="md">
          <Card 
            sx={{ 
              p: { xs: 4, md: 6 },
              background: 'linear-gradient(135deg, #5D5FEF 0%, #7879F1 100%)',
              color: 'white',
              textAlign: 'center',
              position: 'relative',
              overflow: 'hidden',
              borderRadius: 4,
              boxShadow: '0 15px 50px rgba(93, 95, 239, 0.3)'
            }}
          >
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                opacity: 0.1,
                backgroundImage: 'radial-gradient(circle, #ffffff 1px, transparent 1px)',
                backgroundSize: '20px 20px'
              }}
            />

            <Typography variant="h3" gutterBottom>
              Ready to transform your testimonials?
            </Typography>
            <Typography variant="subtitle1" sx={{ mb: 4, opacity: 0.9, maxWidth: 600, mx: 'auto' }}>
              Start free, no credit card required. Upgrade when you need more.
            </Typography>
            <Button 
              variant="contained" 
              size="large"
              component={RouterLink}
              to="/enhance"
              sx={{ 
                px: 5, 
                py: 2,
                bgcolor: 'white',
                color: 'primary.main',
                fontSize: '1.1rem',
                fontWeight: 600,
                boxShadow: '0 8px 20px rgba(255, 255, 255, 0.3)',
                '&:hover': {
                  bgcolor: 'rgba(255, 255, 255, 0.9)',
                  boxShadow: '0 8px 25px rgba(255, 255, 255, 0.4)'
                }
              }}
            >
              Get Started Now
            </Button>
          </Card>
        </Container>
      </Box>
    </Box>
  );
};

export default HomePage;
